class Solution {
    public boolean[] friendRequests(int n, int[][] restrictions, int[][] requests) {
        boolean[] result = new boolean[requests.length];
        int[] visited = new int[n + 1];

        for (int[] request : requests) {
            int u = request[0];
            int v = request[1];

            if (visited[u] == 0) {
                visited[u] = 1;
                for (int i = 0; i <= n; i++) {
                    if (restrictions[u][i] == 0) {
                        visited[v] = 1;
                    }
            }
        }
    }

    return result;
}
